              "content": "/**\n * Squidley V2 — Route Registry\n * ============================================================\n * Single source of truth for every Fastify route module the API exposes.\n *\n * Why this file exists:\n *   - Before this file landed, route registration was split between server.ts\n *     (the documented manifest) and chat.ts (13 sub-mounted route modules\n *     hidden inside `registerChatRoutes`). That made the runtime route\n *     surface impossible to audit without grepping.\n *   - Now: every public route module is declared here. server.ts wires it in.\n *   - The `/_routes` endpoint returns the cheap route-debug inventory.\n *   - `/runtime-truth` is the canonical live operator truth surface.\n *\n * Adding a new route module:\n *   1. import its `registerXyzRoutes` function\n *   2. add an entry to `buildRouteManifest()`\n *   3. that's it — boot will pick it up, /_routes will surface route-debug\n *      inventory and /runtime-truth will surface canonical live truth\n * ============================================================\n */\n\nimport type { FastifyInstance } from \"fastify\";\nimport type { ModelRegistry } from \"../config/model-registry.js\";\nimport type { ForaxDB } from \"../db/forax.js\";\nimport type { CursusDB } from \"../db/cursus.js\";\nimport type { LegatusRuntime } from \"../../../../modules/system/legatus/index.js\";\n\n// Core / always-on\nimport { registerChatRoutes } from \"./chat.js\";\nimport { registerDataRoutes } from \"./data.js\";\nimport { registerMemoryRoutes } from \"./memory.js\";\nimport { registerNousRoutes } from \"./nous.js\";\nimport { registerLegatusRoutes } from \"./legatus.js\";\nimport { registerServiceRoutes } from \"./services.js\";\nimport { registerApprovalRoutes } from \"./approvals.js\";\nimport { registerRunRoutes } from \"./runs.js\";\nimport { registerConcernRoutes } from \"./concerns.js\";\nimport { registerPlannerRoutes } from \"./planner.js\";\nimport { registerRepairMemoryRoutes } from \"./repair-memory.js\";\nimport { registerSelfRepairRoutes } from \"./self-repair.js\";\nimport { registerModuleOwnershipRoutes } from \"./module-ownership.js\";\nimport { registerOpencodeRoutes } from \"./opencode.js\";\nimport { registerEvolutioRoutes } from \"./evolutio.js\";\nimport { registerReviewRoutes } from \"./review.js\";\nimport { registerOccasioRoutes } from \"./occasio.js\";\nimport { registerZendoriumRoutes } from \"./zendorium.js\";\nimport { registerAwarenessRoutes } from \"./awareness.js\";\nimport { registerTasksRoutes } from \"./tasks.js\";\nimport { registerRecoveryRoutes } from \"./recovery.js\";\nimport { registerSystemRoutes } from \"./system.js\";\nimport { registerCrucibleRoutes } from \"./crucible.js\";\nimport { registerPersonalityRoutes } from \"./personality.js\";\nimport { registerMeshRoutes } from \"./mesh.js\";\nimport { registerSquidleyOSRoutes } from \"./squidleyos.js\";\nimport { registerSymposiumRoutes } from \"./symposium.js\";\nimport { registerOBSRoutes } from \"./obs.js\";\nimport { registerDemoRoutes } from \"./demo.js\";\nimport { registerVramGuardRoutes } from \"./vram-guard.js\";\nimport { registerConclaveRoutes } from \"./conclave.js\";\nimport { registerNoctisRoutes } from \"./noctis.js\";\nimport { registerRookeryRoutes } from \"./rookery.js\";\nimport { registerMissionRoutes } from \"./missions.js\";\nimport { registerWebhookRoutes } from \"./webhooks.js\";\nimport { registerPriorityRoutes } from \"./priority.js\";\nimport { registerSkillPackRoutes } from \"./skillpacks.js\";\nimport { registerGmailRoutes } from \"./gmail.js\";\nimport { registerCursusRoutes } from \"./cursus.js\";\nimport { registerVeritorRoutes } from \"./veritor.js\";\nimport { registerCapabilitiesRoutes } from \"./capabilities.js\";\nimport { registerCodingAgentRoutes } from \"./coding-agents.js\";\nimport { registerRickyRoutes } from \"./ricky.js\";\nimport { registerPaedagogusRoutes } from \"./paedagogus.js\";\nimport { registerLlamaCppRoutes } from \"./llamacpp.js\";\nimport { registerMagisterStubsRoutes } from \"./magister-stubs.js\";\nimport { registerBackupRoutes } from \"./backup.js\";\nimport { registerCleanupRoutes } from \"./cleanup.js\";\nimport { registerRuntimeTruthRoutes } from \"./runtime-truth.js\";\n\n// Previously sub-mounted inside chat.ts (now first-class)\nimport { registerCodexRoutes } from \"./codex.js\";\nimport { registerCCRoutes } from \"./cc.js\";\nimport { registerTenticodeRoutes } from \"./tenticode.js\";\nimport { registerFabricaRuntimeRoutes } from \"./fabrica-runtime.js\";\nimport { registerGrimoireScanRoutes } from \"./grimoire-scan.js\";\nimport { registerCrucibleCodeBenchmarkRoutes } from \"./crucible-code-benchmark.js\";\nimport { registerCrucibleProbeRoutes } from \"./crucible-integration-probes.js\";\nimport { registerUnifiedSearchRoutes } from \"./unified-search.js\";\nimport { registerModelFeedbackRoutes } from \"./model-feedback-loop.js\";\nimport { registerProjectContextRoutes } from \"./project-context.js\";\nimport { registerLocalModeRoutes } from \"./local-mode.js\";\nimport { registerSibylRoutes } from \"./sibyl.js\";\nimport { registerImperiumRoutes } from \"./imperium.js\";\nimport { registerKnowledgeRoutes } from \"./knowledge.js\";\n\n/**\n * Each consuming route module narrows `lifecycle` to its own local\n * `PlatformHandle` interface (see e.g. routes/system.ts, routes/data.ts).\n * Keeping this loose here avoids dragging every consumer's narrow shape\n * into a single canonical type — that's a separate normalization pass.\n */\nexport interface PlatformCtx {\n  lifecycle: any;\n}\n\nexport interface RouteRegistryDeps {\n  server: FastifyInstance;\n  getService: <T>(id: string) => T | null;\n  platformCtx: PlatformCtx;\n  registry: ModelRegistry;\n  forax: ForaxDB;\n  cursus: CursusDB;\n  legatus: LegatusRuntime;\n  // Capability gates derived at boot\n  stealth: boolean;\n}\n\nexport interface RouteModule {\n  id: string;\n  enabled: boolean;\n  reason?: string | undefined;\n  /**\n   * The seam group this module belongs to. Used by /_routes for grouping\n   * and by future small-core enforcement to detect over-large surfaces.\n   */\n  group?: \"core\" | \"chat-surface\" | \"agents\" | \"infra\" | \"experience\" | \"diagnostics\" | \"intelligence\";\n  /** Explicit route ownership contract for runtime-truth. */\n  ownership: {\n    prefixes: string[];\n    family?: string | undefined;\n  };\n  register: () => Promise<void> | void;\n}\n\nexport interface RouteRegistrationHooks {\n  onModuleRegisterStart?: (mod: Pick<RouteModule, \"id\" | \"ownership\">) => void;\n  onModuleRegisterEnd?: (mod: Pick<RouteModule, \"id\" | \"ownership\">) => void;\n}\n\nexport interface RouteRegistrationReport {\n  loaded: string[];\n  skipped: Array<{ id: string; reason: string }>;\n  /** Emitted in load order; useful for boot-report parity with the legacy report. */\n  attempted: string[];\n}\n\n/**\n * Build the full route manifest. Pure function of deps — no side effects until\n * `registerAllRoutes` walks it.\n *\n * Sub-mounts that used to live inside `registerChatRoutes` are now declared\n * here. They run BEFORE chat itself so any service/event subscriptions they\n * register are in place when /chat is hit (preserving the previous boot order\n * within chat.ts).\n */\nexport function buildRouteManifest(deps: RouteRegistryDeps): RouteModule[] {\n  const { server, getService, platformCtx, registry, forax, cursus, legatus, stealth } = deps;\n  const s = server as any; // some registrars have stricter Fastify typings\n\n  return [\n    // ── Chat-surface sub-mounts (lifted out of chat.ts) ────────────────────\n    // These run first so their decorators / hooks / shared state are ready\n    // before /chat begins serving. Boot order is preserved from the old\n    // sequence in chat.ts (codex → cc → tenticode → … → imperium).\n    { id: \"codex\",                     group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/forge\", \"/codex\"], family: \"chat_surface\" }, register: () => registerCodexRoutes(s, getService) },\n    { id: \"cc\",                        group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/cc\"], family: \"chat_surface\" }, register: () => registerCCRoutes(s, getService) },\n    { id: \"tenticode\",                 group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/tenticode\"], family: \"chat_surface\" }, register: () => registerTenticodeRoutes(s, getService) },\n    { id: \"fabrica-runtime\",           group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/fabrica\", \"/auriga\"], family: \"chat_surface\" }, register: () => registerFabricaRuntimeRoutes(s, getService) },\n    { id: \"grimoire-scan\",             group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/grimoire/scan\"], family: \"chat_surface\" }, register: () => registerGrimoireScanRoutes(s, getService) },\n    { id: \"crucible-code-benchmark\",   group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/golden\"], family: \"chat_surface\" }, register: () => registerCrucibleCodeBenchmarkRoutes(s, getService) },\n    { id: \"crucible-integration-probes\", group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/health-probes\"], family: \"chat_surface\" }, register: () => registerCrucibleProbeRoutes(s, getService) },\n    { id: \"unified-search\",            group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/search\"], family: \"chat_surface\" }, register: () => registerUnifiedSearchRoutes(s, getService) },\n    { id: \"model-feedback-loop\",       group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/brain-map\"], family: \"chat_surface\" }, register: () => registerModelFeedbackRoutes(s, getService) },\n    { id: \"project-context\",           group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/weather\"], family: \"chat_surface\" }, register: () => registerProjectContextRoutes(s, getService) },\n    { id: \"local-mode\",                group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/provider-manager\", \"/ollama\"], family: \"chat_surface\" }, register: () => registerLocalModeRoutes(s, getService) },\n    { id: \"sibyl\",                     group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/sibyl\", \"/briefings\"], family: \"chat_surface\" }, register: () => registerSibylRoutes(s, getService) },\n    { id: \"imperium\",                  group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/imperium\", \"/pocket\"], family: \"chat_surface\" }, register: () => registerImperiumRoutes(s, getService) },\n    { id: \"knowledge\",                 group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/knowledge\"], family: \"chat_surface\" }, register: () => registerKnowledgeRoutes(s) },\n\n    // ── Core (always loaded) ──────────────────────────────────────────────\n    { id: \"chat\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/chat\", \"/voice\", \"/image\", \"/tools\", \"/tabs\", \"/proposals\", \"/advisor\"], family: \"core_chat\" }, register: () => registerChatRoutes(s, getService, platformCtx) },\n    { id: \"data\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/data\"], family: \"core\" }, register: () => registerDataRoutes(s, getService, platformCtx) },\n    { id: \"memory\",                    group: \"core\", enabled: true, ownership: { prefixes: [\"/memoria\"], family: \"core\" }, register: () => registerMemoryRoutes(s, getService) },\n    { id: \"nous\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/nous\", \"/forax\"], family: \"core_models\" }, register: () => registerNousRoutes(s, getService, registry) },\n    { id: \"legatus\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/legatus\"], family: \"core\" }, register: () => registerLegatusRoutes(s, legatus) },\n    { id: \"services\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/browser\", \"/elevenlabs\", \"/events\"], family: \"core_services\" }, register: () => registerServiceRoutes(s, getService, platformCtx) },\n    { id: \"approvals\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/approvals\"], family: \"core\" }, register: () => registerApprovalRoutes(s, getService) },\n    { id: \"runs\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/runs\"], family: \"core\" }, register: () => registerRunRoutes(s, getService) },\n    { id: \"concerns\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/concerns\"], family: \"core\" }, register: () => registerConcernRoutes(s, getService) },\n    { id: \"planner\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/planner\", \"/plan-executor\"], family: \"core_planning\" }, register: () => registerPlannerRoutes(s, getService, platformCtx) },\n    { id: \"repair-memory\",             group: \"core\", enabled: true, ownership: { prefixes: [\"/repair-memory\"], family: \"core\" }, register: () => registerRepairMemoryRoutes(s, getService) },\n    { id: \"self-repair\",               group: \"core\", enabled: true, ownership: { prefixes: [\"/self-repair\", \"/agent-loop\"], family: \"core_repair\" }, register: () => registerSelfRepairRoutes(s, getService) },\n    { id: \"module-ownership\",          group: \"core\", enabled: true, ownership: { prefixes: [\"/module-ownership\"], family: \"core\" }, register: () => registerModuleOwnershipRoutes(s, getService) },\n    { id: \"opencode\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/opencode\"], family: \"core\" }, register: () => registerOpencodeRoutes(s, getService) },\n    { id: \"evolutio\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/evolutio\"], family: \"core\" }, register: () => registerEvolutioRoutes(s, getService) },\n    { id: \"review\",                    group: \"core\", enabled: true, ownership: { prefixes: [\"/review\"], family: \"core\" }, register: () => registerReviewRoutes(s, getService) },\n    { id: \"occasio\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/occasio\"], family: \"core\" }, register: () => registerOccasioRoutes(s, getService, platformCtx) },\n    { id: \"zendorium\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/zendorium\"], family: \"core\" }, register: () => registerZendoriumRoutes(s, getService) },\n    { id: \"awareness\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/dashboard\", \"/peers\"], family: \"core_awareness\" }, register: () => registerAwarenessRoutes(s, getService, platformCtx) },\n    { id: \"tasks\",                     group: \"core\", enabled: true, ownership: { prefixes: [\"/tasks\"], family: \"core_continuity\" }, register: () => registerTasksRoutes(s, getService) },\n    { id: \"recovery\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/recovery\"], family: \"core_continuity\" }, register: () => registerRecoveryRoutes(s, getService) },\n\n    // ── Intelligence + system surfaces ────────────────────────────────────\n    { id: \"system\",                    group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/system\", \"/platform\", \"/boot\", \"/health\", \"/alive\", \"/ready\", \"/instance\", \"/version\", \"/preflight\", \"/readiness\", \"/_routes\"], family: \"intelligence_system\" }, register: () => registerSystemRoutes(s, getService, platformCtx, registry, forax, legatus) },\n    { id: \"crucible\",                  group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/crucible\", \"/archelon\", \"/augury\"], family: \"intelligence_benchmarks\" }, register: () => registerCrucibleRoutes(s, getService, registry, forax) },\n    { id: \"personality\",               group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/personalities\"], family: \"intelligence\" }, register: () => registerPersonalityRoutes(s, getService, registry) },\n\n    // ── Mesh / multi-node coordination ────────────────────────────────────\n    { id: \"mesh\",                      group: \"infra\", enabled: true, ownership: { prefixes: [\"/mesh\"], family: \"infra\" }, register: () => registerMeshRoutes(s) },\n    { id: \"squidleyos\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/os\"], family: \"infra_os\" }, register: () => registerSquidleyOSRoutes(s, getService) },\n    { id: \"symposium\",                 group: \"infra\", enabled: true, ownership: { prefixes: [\"/symposium\"], family: \"infra\" }, register: () => { registerSymposiumRoutes(s, getService); } },\n    { id: \"obs\",                       group: \"infra\", enabled: true, ownership: { prefixes: [\"/obs\"], family: \"infra\" }, register: () => { registerOBSRoutes(s, getService); } },\n    { id: \"demo\",                      group: \"infra\", enabled: true, ownership: { prefixes: [\"/demo\"], family: \"infra\" }, register: () => { registerDemoRoutes(s, getService); } },\n    { id: \"vram-guard\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/vram-guard\"], family: \"infra\" }, register: () => { registerVramGuardRoutes(s, getService); } },\n    { id: \"conclave\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/conclave\"], family: \"infra\" }, register: () => registerConclaveRoutes(s, getService) },\n    { id: \"noctis\",                    group: \"infra\", enabled: true, ownership: { prefixes: [\"/noctis\"], family: \"infra\" }, register: () => registerNoctisRoutes(s, getService) },\n    { id: \"rookery\",                   group: \"infra\", enabled: true, ownership: { prefixes: [\"/watchtower\"], family: \"infra\" }, register: () => registerRookeryRoutes(s) },\n    { id: \"missions\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/missions\"], family: \"infra\" }, register: () => registerMissionRoutes(s) },\n    { id: \"webhooks\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/hooks\"], family: \"infra\" }, register: () => registerWebhookRoutes(s) },\n    { id: \"priority\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/priority\", \"/reminders\"], family: \"infra\" }, register: () => registerPriorityRoutes(s, getService, platformCtx) },\n    { id: \"skillpacks\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/skillpacks\"], family: \"infra\" }, register: () => registerSkillPackRoutes(s) },\n    { id: \"gmail\",                     group: \"infra\", enabled: true, ownership: { prefixes: [\"/gmail\"], family: \"infra\" }, register: () => registerGmailRoutes(s, getService) },\n\n    // ── Feature modules ──────────────────────────────────────────────────\n    {\n      id: \"cursus\",\n      group: \"experience\",\n      enabled: stealth,\n      reason: !stealth ? \"SQUIDLEY_STEALTH=0 — career module disabled\" : undefined,\n      ownership: { prefixes: [\"/cursus\"], family: \"experience\" },\n      register: () => registerCursusRoutes(s, platformCtx, cursus, legatus),\n    },\n\n    // ── Reliability / coverage ───────────────────────────────────────────\n    { id: \"veritor\",                   group: \"diagnostics\", enabled: true, ownership: { prefixes: [\"/veritor\", \"/diagnose\"], family: \"diagnostics\" }, register: () => registerVeritorRoutes(s, getService) },\n    { id: \"capabilities\",              group: \"diagnostics\", enabled: true, ownership: { prefixes: [\"/capabilities\"], family: \"diagnostics\" }, register: () => registerCapabilitiesRoutes(s, getService, platformCtx) },\n\n    // ── Coding agent + adapters ──────────────────────────────────────────\n    { id: \"coding-agents\",             group: \"agents\", enabled: true, ownership: { prefixes: [\"/agents\", \"/codex/sessions\"], family: \"agents\" }, register: () => registerCodingAgentRoutes(s, getService) },\n    { id: \"ricky\",                     group: \"agents\", enabled: true, ownership: { prefixes: [\"/ricky\"], family: \"agents\" }, register: () => registerRickyRoutes(s, getService) },\n    { id: \"paedagogus\",                group: \"agents\", enabled: true, ownership: { prefixes: [\"/paedagogus\"], family: \"agents\" }, register: () => registerPaedagogusRoutes(s, getService) },\n\n    // ── Provider control surfaces ───────────────────────────────────────\n    // llama.cpp / Ollama status + test endpoints. Used by the Nous LlamaCpp\n    // page; was previously written but never registered, so the UI silently\n    // 404'd. Now first-class.\n    { id: \"llamacpp\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/llamacpp\"], family: \"infra\" }, register: () => registerLlamaCppRoutes(s) },\n\n    // Magister truth-gap stubs — UI calls these paths but the real routes\n    // were never built. Stubs return 501 so the gap is visible (in /_routes\n    // and in UI badges) instead of producing silent 404s.\n    { id: \"magister-stubs\",            group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/magister\"], family: \"chat_surface\" }, register: () => registerMagisterStubsRoutes(s) },\n\n    // Backup orchestrator + cleanup governance (v1 — quarantine-only).\n    { id: \"backup\",                    group: \"infra\", enabled: true, ownership: { prefixes: [\"/backup\"], family: \"infra\" }, register: () => registerBackupRoutes(s, getService) },\n    { id: \"cleanup\",                   group: \"infra\", enabled: true, ownership: { prefixes: [\"/cleanup\", \"/rollback\"], family: \"infra\" }, register: () => registerCleanupRoutes(s, getService) },\n\n    // Canonical runtime-truth surface + phase-aware readiness probe.\n    { id: \"runtime-truth\",             group: \"core\", enabled: true, ownership: { prefixes: [\"/runtime-truth\", \"/readiness\"], family: \"core_truth\" }, register: () => registerRuntimeTruthRoutes(s, getService) },\n    // NOTE: All route modules above are registered in boot order; additions must follow the group conventions above.\n  ];\n}\n\n/**\n * Walk the manifest, register every enabled module, return a load/skip report.\n * Failures are logged via Fastify and reported as `skipped` — they do not abort\n * boot. This matches the prior behavior in server.ts.\n */\nexport async function registerAllRoutes(deps: RouteRegistryDeps, hooks: RouteRegistrationHooks = {}): Promise<RouteRegistrationReport> {\n  const manifest = buildRouteManifest(deps);\n  const report: RouteRegistrationReport = { loaded: [], skipped: [], attempted: [] };\n\n  for (const mod of manifest) {\n    report.attempted.push(mod.id);\n    if (!mod.enabled) {\n      report.skipped.push({ id: mod.id, reason: mod.reason ?? \"disabled\" });\n      continue;\n    }\n    try {\n      hooks.onModuleRegisterStart?.(mod);\n      await mod.register();\n      hooks.onModuleRegisterEnd?.(mod);\n      report.loaded.push(mod.id);\n    } catch (err) {\n      hooks.onModuleRegisterEnd?.(mod);\n      report.skipped.push({ id: mod.id, reason: `registration failed: ${String(err).slice(0, 200)}` });\n      deps.server.log.error({ event: \"route-module:failed\", module: mod.id, error: String(err) });\n    }\n  }\n\n  return report;\n}\n\n/**\n * Snapshot of route groups (without registering anything). Useful for /_routes\n * to surface \"what would have been loaded\" alongside the actual report.\n */\nexport function describeRouteManifest(deps: RouteRegistryDeps): Array<{ id: string; group: string; enabled: boolean; prefixes: string[]; family?: string; reason?: string }> {\n  return buildRouteManifest(deps).map((m) => ({\n    id: m.id,\n    group: m.group ?? \"ungrouped\",\n    enabled: m.enabled,\n    prefixes: [...m.ownership.prefixes],\n    ...(m.ownership.family ? { family: m.ownership.family } : {}),\n    ...(m.reason ? { reason: m.reason } : {}),\n  }));\n}\n",
              "lineCount": 308
