              "path": "apps/api/src/routes/index.ts",
              "content": "/**\n * Squidley V2 — Route Registry\n * ============================================================\n * Single source of truth for every Fastify route module the API exposes.\n *\n * Why this file exists:\n *   - Before this file landed, route registration was split between server.ts\n *     (the documented manifest) and chat.ts (13 sub-mounted route modules\n *     hidden inside `registerChatRoutes`). That made the runtime route\n *     surface impossible to audit without grepping.\n *   - Now: every public route module is declared here. server.ts wires it in.\n *   - The `/_routes` endpoint returns the cheap route-debug inventory.\n *   - `/runtime-truth` is the canonical live operator truth surface.\n *\n * Adding a new route module:\n *   1. import its `registerXyzRoutes` function\n *   2. add an entry to `buildRouteManifest()`\n *   3. that's it — boot will pick it up, /_routes will surface route-debug\n *      inventory and /runtime-truth will surface canonical live truth\n * ============================================================\n */\n\nimport type { FastifyInstance } from \"fastify\";\nimport type { ModelRegistry } from \"../config/model-registry.js\";\nimport type { ForaxDB } from \"../db/forax.js\";\nimport type { CursusDB } from \"../db/cursus.js\";\nimport type { LegatusRuntime } from \"../../../../modules/system/legatus/index.js\";\n\n// Core / always-on\nimport { registerChatRoutes } from \"./chat.js\";\nimport { registerDataRoutes } from \"./data.js\";\nimport { registerMemoryRoutes } from \"./memory.js\";\nimport { registerNousRoutes } from \"./nous.js\";\nimport { registerLegatusRoutes } from \"./legatus.js\";\nimport { registerServiceRoutes } from \"./services.js\";\nimport { registerApprovalRoutes } from \"./approvals.js\";\nimport { registerRunRoutes } from \"./runs.js\";\nimport { registerConcernRoutes } from \"./concerns.js\";\nimport { registerPlannerRoutes } from \"./planner.js\";\nimport { registerRepairMemoryRoutes } from \"./repair-memory.js\";\nimport { registerSelfRepairRoutes } from \"./self-repair.js\";\nimport { registerModuleOwnershipRoutes } from \"./module-ownership.js\";\nimport { registerOpencodeRoutes } from \"./opencode.js\";\nimport { registerEvolutioRoutes } from \"./evolutio.js\";\nimport { registerReviewRoutes } from \"./review.js\";\nimport { registerOccasioRoutes } from \"./occasio.js\";\nimport { registerZendoriumRoutes } from \"./zendorium.js\";\nimport { registerAwarenessRoutes } from \"./awareness.js\";\nimport { registerTasksRoutes } from \"./tasks.js\";\nimport { registerRecoveryRoutes } from \"./recovery.js\";\nimport { registerSystemRoutes } from \"./system.js\";\nimport { registerCrucibleRoutes } from \"./crucible.js\";\nimport { registerPersonalityRoutes } from \"./personality.js\";\nimport { registerMeshRoutes } from \"./mesh.js\";\nimport { registerSquidleyOSRoutes } from \"./squidleyos.js\";\nimport { registerSymposiumRoutes } from \"./symposium.js\";\nimport { registerOBSRoutes } from \"./obs.js\";\nimport { registerDemoRoutes } from \"./demo.js\";\nimport { registerVramGuardRoutes } from \"./vram-guard.js\";\nimport { registerConclaveRoutes } from \"./conclave.js\";\nimport { registerNoctisRoutes } from \"./noctis.js\";\nimport { registerRookeryRoutes } from \"./rookery.js\";\nimport { registerMissionRoutes } from \"./missions.js\";\nimport { registerWebhookRoutes } from \"./webhooks.js\";\nimport { registerPriorityRoutes } from \"./priority.js\";\nimport { registerSkillPackRoutes } from \"./skillpacks.js\";\nimport { registerGmailRoutes } from \"./gmail.js\";\nimport { registerCursusRoutes } from \"./cursus.js\";\nimport { registerVeritorRoutes } from \"./veritor.js\";\nimport { registerCapabilitiesRoutes } from \"./capabilities.js\";\nimport { registerCodingAgentRoutes } from \"./coding-agents.js\";\nimport { registerRickyRoutes } from \"./ricky.js\";\nimport { registerPaedagogusRoutes } from \"./paedagogus.js\";\nimport { registerLlamaCppRoutes } from \"./llamacpp.js\";\nimport { registerMagisterStubsRoutes } from \"./magister-stubs.js\";\nimport { registerBackupRoutes } from \"./backup.js\";\nimport { registerCleanupRoutes } from \"./cleanup.js\";\nimport { registerRuntimeTruthRoutes } from \"./runtime-truth.js\";\n\n// Previously sub-mounted inside chat.ts (now first-class)\nimport { registerCodexRoutes } from \"./codex.js\";\nimport { registerCCRoutes } from \"./cc.js\";\nimport { registerTenticodeRoutes } from \"./tenticode.js\";\nimport { registerFabricaRuntimeRoutes } from \"./fabrica-runtime.js\";\nimport { registerGrimoireScanRoutes } from \"./grimoire-scan.js\";\nimport { registerCrucibleCodeBenchmarkRoutes } from \"./crucible-code-benchmark.js\";\nimport { registerCrucibleProbeRoutes } from \"./crucible-integration-probes.js\";\nimport { registerUnifiedSearchRoutes } from \"./unified-search.js\";\nimport { registerModelFeedbackRoutes } from \"./model-feedback-loop.js\";\nimport { registerProjectContextRoutes } from \"./project-context.js\";\nimport { registerLocalModeRoutes } from \"./local-mode.js\";\nimport { registerSibylRoutes } from \"./sibyl.js\";\nimport { registerImperiumRoutes } from \"./imperium.js\";\nimport { registerKnowledgeRoutes } from \"./knowledge.js\";\n\n/**\n * Each consuming route module narrows `lifecycle` to its own local\n * `PlatformHandle` interface (see e.g. routes/system.ts, routes/data.ts).\n * Keeping this loose here avoids dragging every consumer's narrow shape\n * into a single canonical type — that's a separate normalization pass.\n */\nexport interface PlatformCtx {\n  lifecycle: any;\n}\n\nexport interface RouteRegistryDeps {\n  server: FastifyInstance;\n  getService: <T>(id: string) => T | null;\n  platformCtx: PlatformCtx;\n  registry: ModelRegistry;\n  forax: ForaxDB;\n  cursus: CursusDB;\n  legatus: LegatusRuntime;\n  // Capability gates derived at boot\n  stealth: boolean;\n}\n\nexport interface RouteModule {\n  id: string;\n  enabled: boolean;\n  reason?: string | undefined;\n  /**\n   * The seam group this module belongs to. Used by /_routes for grouping\n   * and by future small-core enforcement to detect over-large surfaces.\n   */\n  group?: \"core\" | \"chat-surface\" | \"agents\" | \"infra\" | \"experience\" | \"diagnostics\" | \"intelligence\";\n  /** Explicit route ownership contract for runtime-truth. */\n  ownership: {\n    prefixes: string[];\n    family?: string | undefined;\n  };\n  register: () => Promise<void> | void;\n}\n\nexport interface RouteRegistrationHooks {\n  onModuleRegisterStart?: (mod: Pick<RouteModule, \"id\" | \"ownership\">) => void;\n  onModuleRegisterEnd?: (mod: Pick<RouteModule, \"id\" | \"ownership\">) => void;\n}\n\nexport interface RouteRegistrationReport {\n  loaded: string[];\n  skipped: Array<{ id: string; reason: string }>;\n  /** Emitted in load order; useful for boot-report parity with the legacy report. */\n  attempted: string[];\n}\n\n/**\n * Build the full route manifest. Pure function of deps — no side effects until\n * `registerAllRoutes` walks it.\n *\n * Sub-mounts that used to live inside `registerChatRoutes` are now declared\n * here. They run BEFORE chat itself so any service/event subscriptions they\n * register are in place when /chat is hit (preserving the previous boot order\n * within chat.ts).\n */\nexport function buildRouteManifest(deps: RouteRegistryDeps): RouteModule[] {\n  const { server, getService, platformCtx, registry, forax, cursus, legatus, stealth } = deps;\n  const s = server as any; // some registrars have stricter Fastify typings\n\n  return [\n    // ── Chat-surface sub-mounts (lifted out of chat.ts) ────────────────────\n    // These run first so their decorators / hooks / shared state are ready\n    // before /chat begins serving. Boot order is preserved from the old\n    // sequence in chat.ts (codex → cc → tenticode → … → imperium).\n    { id: \"codex\",                     group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/forge\", \"/codex\"], family: \"chat_surface\" }, register: () => registerCodexRoutes(s, getService) },\n    { id: \"cc\",                        group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/cc\"], family: \"chat_surface\" }, register: () => registerCCRoutes(s, getService) },\n    { id: \"tenticode\",                 group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/tenticode\"], family: \"chat_surface\" }, register: () => registerTenticodeRoutes(s, getService) },\n    { id: \"fabrica-runtime\",           group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/fabrica\", \"/auriga\"], family: \"chat_surface\" }, register: () => registerFabricaRuntimeRoutes(s, getService) },\n    { id: \"grimoire-scan\",             group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/grimoire/scan\"], family: \"chat_surface\" }, register: () => registerGrimoireScanRoutes(s, getService) },\n    { id: \"crucible-code-benchmark\",   group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/golden\"], family: \"chat_surface\" }, register: () => registerCrucibleCodeBenchmarkRoutes(s, getService) },\n    { id: \"crucible-integration-probes\", group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/health-probes\"], family: \"chat_surface\" }, register: () => registerCrucibleProbeRoutes(s, getService) },\n    { id: \"unified-search\",            group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/search\"], family: \"chat_surface\" }, register: () => registerUnifiedSearchRoutes(s, getService) },\n    { id: \"model-feedback-loop\",       group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/brain-map\"], family: \"chat_surface\" }, register: () => registerModelFeedbackRoutes(s, getService) },\n    { id: \"project-context\",           group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/weather\"], family: \"chat_surface\" }, register: () => registerProjectContextRoutes(s, getService) },\n    { id: \"local-mode\",                group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/provider-manager\", \"/ollama\"], family: \"chat_surface\" }, register: () => registerLocalModeRoutes(s, getService) },\n    { id: \"sibyl\",                     group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/sibyl\", \"/briefings\"], family: \"chat_surface\" }, register: () => registerSibylRoutes(s, getService) },\n    { id: \"imperium\",                  group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/imperium\", \"/pocket\"], family: \"chat_surface\" }, register: () => registerImperiumRoutes(s, getService) },\n    { id: \"knowledge\",                 group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/knowledge\"], family: \"chat_surface\" }, register: () => registerKnowledgeRoutes(s) },\n\n    // ── Core (always loaded) ──────────────────────────────────────────────\n    { id: \"chat\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/chat\", \"/voice\", \"/image\", \"/tools\", \"/tabs\", \"/proposals\", \"/advisor\"], family: \"core_chat\" }, register: () => registerChatRoutes(s, getService, platformCtx) },\n    { id: \"data\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/data\"], family: \"core\" }, register: () => registerDataRoutes(s, getService, platformCtx) },\n    { id: \"memory\",                    group: \"core\", enabled: true, ownership: { prefixes: [\"/memoria\"], family: \"core\" }, register: () => registerMemoryRoutes(s, getService) },\n    { id: \"nous\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/nous\", \"/forax\"], family: \"core_models\" }, register: () => registerNousRoutes(s, getService, registry) },\n    { id: \"legatus\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/legatus\"], family: \"core\" }, register: () => registerLegatusRoutes(s, legatus) },\n    { id: \"services\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/browser\", \"/elevenlabs\", \"/events\"], family: \"core_services\" }, register: () => registerServiceRoutes(s, getService, platformCtx) },\n    { id: \"approvals\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/approvals\"], family: \"core\" }, register: () => registerApprovalRoutes(s, getService) },\n    { id: \"runs\",                      group: \"core\", enabled: true, ownership: { prefixes: [\"/runs\"], family: \"core\" }, register: () => registerRunRoutes(s, getService) },\n    { id: \"concerns\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/concerns\"], family: \"core\" }, register: () => registerConcernRoutes(s, getService) },\n    { id: \"planner\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/planner\", \"/plan-executor\"], family: \"core_planning\" }, register: () => registerPlannerRoutes(s, getService, platformCtx) },\n    { id: \"repair-memory\",             group: \"core\", enabled: true, ownership: { prefixes: [\"/repair-memory\"], family: \"core\" }, register: () => registerRepairMemoryRoutes(s, getService) },\n    { id: \"self-repair\",               group: \"core\", enabled: true, ownership: { prefixes: [\"/self-repair\", \"/agent-loop\"], family: \"core_repair\" }, register: () => registerSelfRepairRoutes(s, getService) },\n    { id: \"module-ownership\",          group: \"core\", enabled: true, ownership: { prefixes: [\"/module-ownership\"], family: \"core\" }, register: () => registerModuleOwnershipRoutes(s, getService) },\n    { id: \"opencode\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/opencode\"], family: \"core\" }, register: () => registerOpencodeRoutes(s, getService) },\n    { id: \"evolutio\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/evolutio\"], family: \"core\" }, register: () => registerEvolutioRoutes(s, getService) },\n    { id: \"review\",                    group: \"core\", enabled: true, ownership: { prefixes: [\"/review\"], family: \"core\" }, register: () => registerReviewRoutes(s, getService) },\n    { id: \"occasio\",                   group: \"core\", enabled: true, ownership: { prefixes: [\"/occasio\"], family: \"core\" }, register: () => registerOccasioRoutes(s, getService, platformCtx) },\n    { id: \"zendorium\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/zendorium\"], family: \"core\" }, register: () => registerZendoriumRoutes(s, getService) },\n    { id: \"awareness\",                 group: \"core\", enabled: true, ownership: { prefixes: [\"/dashboard\", \"/peers\"], family: \"core_awareness\" }, register: () => registerAwarenessRoutes(s, getService, platformCtx) },\n    { id: \"tasks\",                     group: \"core\", enabled: true, ownership: { prefixes: [\"/tasks\"], family: \"core_continuity\" }, register: () => registerTasksRoutes(s, getService) },\n    { id: \"recovery\",                  group: \"core\", enabled: true, ownership: { prefixes: [\"/recovery\"], family: \"core_continuity\" }, register: () => registerRecoveryRoutes(s, getService) },\n\n    // ── Intelligence + system surfaces ────────────────────────────────────\n    { id: \"system\",                    group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/system\", \"/platform\", \"/boot\", \"/health\", \"/alive\", \"/ready\", \"/instance\", \"/version\", \"/preflight\", \"/readiness\", \"/_routes\"], family: \"intelligence_system\" }, register: () => registerSystemRoutes(s, getService, platformCtx, registry, forax, legatus) },\n    { id: \"crucible\",                  group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/crucible\", \"/archelon\", \"/augury\"], family: \"intelligence_benchmarks\" }, register: () => registerCrucibleRoutes(s, getService, registry, forax) },\n    { id: \"personality\",               group: \"intelligence\", enabled: true, ownership: { prefixes: [\"/personalities\"], family: \"intelligence\" }, register: () => registerPersonalityRoutes(s, getService, registry) },\n\n    // ── Mesh / multi-node coordination ────────────────────────────────────\n    { id: \"mesh\",                      group: \"infra\", enabled: true, ownership: { prefixes: [\"/mesh\"], family: \"infra\" }, register: () => registerMeshRoutes(s) },\n    { id: \"squidleyos\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/os\"], family: \"infra_os\" }, register: () => registerSquidleyOSRoutes(s, getService) },\n    { id: \"symposium\",                 group: \"infra\", enabled: true, ownership: { prefixes: [\"/symposium\"], family: \"infra\" }, register: () => { registerSymposiumRoutes(s, getService); } },\n    { id: \"obs\",                       group: \"infra\", enabled: true, ownership: { prefixes: [\"/obs\"], family: \"infra\" }, register: () => { registerOBSRoutes(s, getService); } },\n    { id: \"demo\",                      group: \"infra\", enabled: true, ownership: { prefixes: [\"/demo\"], family: \"infra\" }, register: () => { registerDemoRoutes(s, getService); } },\n    { id: \"vram-guard\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/vram-guard\"], family: \"infra\" }, register: () => { registerVramGuardRoutes(s, getService); } },\n    { id: \"conclave\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/conclave\"], family: \"infra\" }, register: () => registerConclaveRoutes(s, getService) },\n    { id: \"noctis\",                    group: \"infra\", enabled: true, ownership: { prefixes: [\"/noctis\"], family: \"infra\" }, register: () => registerNoctisRoutes(s, getService) },\n    { id: \"rookery\",                   group: \"infra\", enabled: true, ownership: { prefixes: [\"/watchtower\"], family: \"infra\" }, register: () => registerRookeryRoutes(s) },\n    { id: \"missions\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/missions\"], family: \"infra\" }, register: () => registerMissionRoutes(s) },\n    { id: \"webhooks\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/hooks\"], family: \"infra\" }, register: () => registerWebhookRoutes(s) },\n    { id: \"priority\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/priority\", \"/reminders\"], family: \"infra\" }, register: () => registerPriorityRoutes(s, getService, platformCtx) },\n    { id: \"skillpacks\",                group: \"infra\", enabled: true, ownership: { prefixes: [\"/skillpacks\"], family: \"infra\" }, register: () => registerSkillPackRoutes(s) },\n    { id: \"gmail\",                     group: \"infra\", enabled: true, ownership: { prefixes: [\"/gmail\"], family: \"infra\" }, register: () => registerGmailRoutes(s, getService) },\n\n    // ── Feature modules ──────────────────────────────────────────────────\n    {\n      id: \"cursus\",\n      group: \"experience\",\n      enabled: stealth,\n      reason: !stealth ? \"SQUIDLEY_STEALTH=0 — career module disabled\" : undefined,\n      ownership: { prefixes: [\"/cursus\"], family: \"experience\" },\n      register: () => registerCursusRoutes(s, platformCtx, cursus, legatus),\n    },\n\n    // ── Reliability / coverage ───────────────────────────────────────────\n    { id: \"veritor\",                   group: \"diagnostics\", enabled: true, ownership: { prefixes: [\"/veritor\", \"/diagnose\"], family: \"diagnostics\" }, register: () => registerVeritorRoutes(s, getService) },\n    { id: \"capabilities\",              group: \"diagnostics\", enabled: true, ownership: { prefixes: [\"/capabilities\"], family: \"diagnostics\" }, register: () => registerCapabilitiesRoutes(s, getService, platformCtx) },\n\n    // ── Coding agent + adapters ──────────────────────────────────────────\n    { id: \"coding-agents\",             group: \"agents\", enabled: true, ownership: { prefixes: [\"/agents\", \"/codex/sessions\"], family: \"agents\" }, register: () => registerCodingAgentRoutes(s, getService) },\n    { id: \"ricky\",                     group: \"agents\", enabled: true, ownership: { prefixes: [\"/ricky\"], family: \"agents\" }, register: () => registerRickyRoutes(s, getService) },\n    { id: \"paedagogus\",                group: \"agents\", enabled: true, ownership: { prefixes: [\"/paedagogus\"], family: \"agents\" }, register: () => registerPaedagogusRoutes(s, getService) },\n\n    // ── Provider control surfaces ───────────────────────────────────────\n    // llama.cpp / Ollama status + test endpoints. Used by the Nous LlamaCpp\n    // page; was previously written but never registered, so the UI silently\n    // 404'd. Now first-class.\n    { id: \"llamacpp\",                  group: \"infra\", enabled: true, ownership: { prefixes: [\"/llamacpp\"], family: \"infra\" }, register: () => registerLlamaCppRoutes(s) },\n\n    // Magister truth-gap stubs — UI calls these paths but the real routes\n    // were never built. Stubs return 501 so the gap is visible (in /_routes\n    // and in UI badges) instead of producing silent 404s.\n    { id: \"magister-stubs\",            group: \"chat-surface\", enabled: true, ownership: { prefixes: [\"/magister\"], family: \"chat_surface\" }, register: () => registerMagisterStubsRoutes(s) },\n\n    // Backup orchestrator + cleanup governance (v1 — quarantine-only).\n    { id: \"backup\",                    group: \"infra\", enabled: true, ownership: { prefixes: [\"/backup\"], family: \"infra\" }, register: () => registerBackupRoutes(s, getService) },\n    { id: \"cleanup\",                   group: \"infra\", enabled: true, ownership: { prefixes: [\"/cleanup\", \"/rollback\"], family: \"infra\" }, register: () => registerCleanupRoutes(s, getService) },\n\n    // Canonical runtime-truth surface + phase-aware readiness probe.\n    { id: \"runtime-truth\",             group: \"core\", enabled: true, ownership: { prefixes: [\"/runtime-truth\", \"/readiness\"], family: \"core_truth\" }, register: () => registerRuntimeTruthRoutes(s, getService) },\n    // NOTE: All route modules above are registered in boot order; additions must follow the group conventions above.\n  ];\n}\n\n/**\n * Walk the manifest, register every enabled module, return a load/skip report.\n * Failures are logged via Fastify and reported as `skipped` — they do not abort\n * boot. This matches the prior behavior in server.ts.\n */\nexport async function registerAllRoutes(deps: RouteRegistryDeps, hooks: RouteRegistrationHooks = {}): Promise<RouteRegistrationReport> {\n  const manifest = buildRouteManifest(deps);\n  const report: RouteRegistrationReport = { loaded: [], skipped: [], attempted: [] };\n\n  for (const mod of manifest) {\n    report.attempted.push(mod.id);\n    if (!mod.enabled) {\n      report.skipped.push({ id: mod.id, reason: mod.reason ?? \"disabled\" });\n      continue;\n    }\n    try {\n      hooks.onModuleRegisterStart?.(mod);\n      await mod.register();\n      hooks.onModuleRegisterEnd?.(mod);\n      report.loaded.push(mod.id);\n    } catch (err) {\n      hooks.onModuleRegisterEnd?.(mod);\n      report.skipped.push({ id: mod.id, reason: `registration failed: ${String(err).slice(0, 200)}` });\n      deps.server.log.error({ event: \"route-module:failed\", module: mod.id, error: String(err) });\n    }\n  }\n\n  return report;\n}\n\n/**\n * Snapshot of route groups (without registering anything). Useful for /_routes\n * to surface \"what would have been loaded\" alongside the actual report.\n */\nexport function describeRouteManifest(deps: RouteRegistryDeps): Array<{ id: string; group: string; enabled: boolean; prefixes: string[]; family?: string; reason?: string }> {\n  return buildRouteManifest(deps).map((m) => ({\n    id: m.id,\n    group: m.group ?? \"ungrouped\",\n    enabled: m.enabled,\n    prefixes: [...m.ownership.prefixes],\n    ...(m.ownership.family ? { family: m.ownership.family } : {}),\n    ...(m.reason ? { reason: m.reason } : {}),\n  }));\n}\n",
              "lineCount": 308
            },
            {
              "path": "apps/api/src/config/advisor-policy.ts",
              "content": "/**\n * Advisory Model Escalation — Policy Config\n * ============================================\n * Escalation ladder, heuristic thresholds, keyword lists.\n * Mutable at runtime — UI can toggle enable/disable.\n */\n\nexport interface AdvisorPolicy {\n  /** Global kill switch */\n  enabled: boolean;\n\n  /**\n   * Escalation ladder — ordered low → high capability.\n   * Each entry matches model name patterns (case-insensitive substring).\n   * A model can only escalate to entries ABOVE it in the ladder.\n   */\n  ladder: Array<{\n    /** Human label shown in the suggestion */\n    label: string;\n    /** Patterns to match against model name/id (any match = this tier) */\n    patterns: string[];\n    /** The model string to pass to the provider when escalating */\n    modelId: string;\n    /** Provider hint */\n    provider: string;\n  }>;\n\n  /** Uncertainty signal phrases in model responses */\n  uncertaintyPhrases: string[];\n\n  /** Keywords in user messages that indicate complex requests */\n  complexityKeywords: string[];\n\n  /** Token estimate threshold — user messages above this are \"complex\" */\n  complexTokenThreshold: number;\n\n  /** Minimum response tokens expected for a complex request */\n  shortResponseThreshold: number;\n\n  /** How many consecutive uncertain/short responses before suggesting */\n  consecutiveThreshold: number;\n}\n\nexport const advisorPolicy: AdvisorPolicy = {\n  enabled: true,\n\n  ladder: [\n    {\n      label: \"MiMo Flash\",\n      patterns: [\"mimo-flash\", \"mimo-v2-flash\", \"moonshotai/mimo-flash\", \"xiaomi/mimo-v2-flash\"],\n      modelId: \"xiaomi/mimo-v2-flash-20251210\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"MiMo Pro\",\n      patterns: [\"mimo-pro\", \"mimo-v2-pro\", \"mimo pro\", \"moonshotai/mimo-pro\", \"xiaomi/mimo-v2-pro\"],\n      modelId: \"xiaomi/mimo-v2-pro-20251210\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"Claude Sonnet 4.6\",\n      patterns: [\"claude-sonnet\", \"sonnet-4\", \"sonnet 4\", \"claude-4\"],\n      modelId: \"anthropic/claude-sonnet-4-6\",\n      provider: \"openrouter\",\n    },\n    {\n      label: \"Claude Opus 4.6\",\n      patterns: [\"claude-opus\", \"opus-4\", \"opus 4\"],\n      modelId: \"anthropic/claude-opus-4-6\",\n      provider: \"openrouter\",\n    },\n  ],\n\n  uncertaintyPhrases: [\n    \"i'm not sure\",\n    \"i don't know\",\n    \"i can't\",\n    \"i cannot\",\n    \"beyond my\",\n    \"unable to\",\n    \"i'm unable\",\n    \"i don't have the ability\",\n    \"outside my capabilities\",\n    \"not equipped to\",\n    \"i lack the\",\n    \"this is beyond\",\n    \"i may not be the best\",\n    \"you might want to use a more\",\n    \"a more capable model\",\n    \"i'm limited\",\n    \"my training\",\n    \"as a language model\",\n  ],\n\n  complexityKeywords: [\n    \"analyze\",\n    \"compare\",\n    \"reason through\",\n    \"architecture\",\n    \"security\",\n    \"audit\",\n    \"deep dive\",\n    \"explain in detail\",\n    \"trace through\",\n    \"step by step\",\n    \"pros and cons\",\n    \"trade-offs\",\n    \"tradeoffs\",\n    \"root cause\",\n    \"debug\",\n    \"refactor\",\n    \"design pattern\",\n    \"evaluate\",\n    \"comprehensive\",\n    \"thorough\",\n  ],\n\n  complexTokenThreshold: 800,\n  shortResponseThreshold: 150,\n  consecutiveThreshold: 2,\n};\n",
              "lineCount": 122
            },
            {
              "path": "apps/api/src/config/model-registry.ts",
              "content": "/**\n * Squidley V2 — Nous Model Registry\n * ============================================================\n * SQLite-backed runtime model registry.\n * Bootstraps from lite-defaults.json when empty.\n * ============================================================\n */\n\nimport Database from \"better-sqlite3\";\nimport { randomUUID } from \"node:crypto\";\nimport { join, resolve } from \"node:path\";\nimport { mkdirSync, readFileSync } from \"node:fs\";\nimport type { ModuleContract } from \"@squidley/core\";\n\nexport type ModelRole =\n  | \"chat\" | \"code\" | \"agent\" | \"classify\" | \"vision\" | \"reason\" | \"grimoire\" | \"roleplay\"\n  | \"fallback-chat\" | \"fallback-code\" | \"agent-planner\" | \"vision-ocr\" | \"code-review\"\n  | \"ricky-builder\" | \"ricky-reviewer\" | \"ricky-planner\" | \"ricky-qc\" | \"ricky-vision\";\n\nexport const ALL_MODEL_ROLES: ModelRole[] = [\n  \"chat\", \"code\", \"agent\", \"classify\", \"vision\", \"reason\", \"grimoire\", \"roleplay\",\n  \"fallback-chat\", \"fallback-code\", \"agent-planner\", \"vision-ocr\", \"code-review\",\n  \"ricky-builder\", \"ricky-reviewer\", \"ricky-planner\", \"ricky-qc\", \"ricky-vision\",\n];\n\nexport interface ModelEntry {\n  id: string;\n  name: string;\n  model: string;\n  provider: string;\n  tier: 0 | 1 | 2 | 3;\n  roles: ModelRole[];\n  max_tokens: number | null;\n  active: boolean;\n  notes: string | null;\n  cost_per_m_input: number | null;\n  cost_per_m_output: number | null;\n  thinking_mode: \"default\" | \"enabled\" | \"disabled\";\n  created_at: string;\n}\n\ninterface ModelRow {\n  id: string;\n  name: string;\n  model: string;\n  provider: string;\n  tier: 0 | 1 | 2 | 3;\n  max_tokens: number | null;\n  active: 0 | 1;\n  notes: string | null;\n  cost_per_m_input: number | null;\n  cost_per_m_output: number | null;\n  thinking_mode: string | null;\n  created_at: string;\n}\n\ninterface AssignmentRow {\n  role: ModelRole;\n  model_id: string;\n}\n\ninterface LiteDefaults {\n  defaults: Record<string, { model: string; provider: string } | null>;\n  liteMode: boolean;\n  cloudEnabled: boolean;\n}\n\nexport type RegistryTrust = \"trusted\" | \"verified\" | \"degraded\";\n\nexport interface ModelRegistryHealth {\n  trust: RegistryTrust;\n  mode: \"lite\" | \"full\";\n  dbPath: string;\n  contract: ModuleContract;\n  hint: string | null;\n  cloudEnabled: boolean;\n  bootstrapSource: \"database\" | \"lite-defaults\";\n}\n\nexport const NOUS_CONTRACT: ModuleContract = {\n  promise: \"Maintain model registry and role assignments — always know what model handles each task\",\n  proofPath: \"nous-registry.db — inspectable, GET /nous/models returns live state\",\n  degradedBehavior: \"Falls back to lite-defaults.json if registry empty or corrupt\",\n  failureOwner: \"nous\",\n};\n\nconst CORE_ROLE_REQUIREMENTS: ModelRole[] = [\n  \"chat\",\n  \"code\",\n  \"agent\",\n  \"classify\",\n  \"reason\",\n  \"grimoire\",\n  \"agent-planner\",\n  \"code-review\",\n];\n\nconst PROVIDER_SERVICE_IDS: Record<string, string> = {\n  ollama: \"squidley.integration.provider-ollama\",\n  llamacpp: \"squidley.integration.provider-llamacpp\",\n  openrouter: \"squidley.integration.provider-openrouter\",\n  \"openrouter-free\": \"squidley.integration.provider-openrouter-free\",\n  openai: \"squidley.integration.provider-openai\",\n  anthropic: \"squidley.integration.provider-anthropic\",\n  modelstudio: \"squidley.integration.provider-modelstudio\",\n  zai: \"squidley.integration.provider-zai\",\n  minimax: \"squidley.integration.provider-minimax\",\n  groq: \"squidley.integration.provider-groq\",\n  \"google-ai-studio\": \"squidley.integration.provider-google-ai-studio\",\n  cerebras: \"squidley.integration.provider-cerebras\",\n};\n\ntype BuiltinTierCatalogEntry = {\n  name: string;\n  model: string;\n  provider: string;\n  tier: 0 | 1 | 2 | 3;\n  notes: string;\n  max_tokens?: number | null;\n  cost_per_m_input?: number | null;\n  cost_per_m_output?: number | null;\n  thinking_mode?: \"default\" | \"enabled\" | \"disabled\";\n  active?: boolean;\n};\n\nconst BUILTIN_TIER_CATALOG: BuiltinTierCatalogEntry[] = [\n  { name: \"Groq Llama 3.3 70B Versatile\", model: \"llama-3.3-70b-versatile\", provider: \"squidley.integration.provider-groq\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Groq Mixtral 8x7B\", model: \"mixtral-8x7b-32768\", provider: \"squidley.integration.provider-groq\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Groq Gemma 2 9B\", model: \"gemma2-9b-it\", provider: \"squidley.integration.provider-groq\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Google Gemini 2.0 Flash\", model: \"gemini-2.0-flash\", provider: \"squidley.integration.provider-google-ai-studio\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Google Gemini 1.5 Flash\", model: \"gemini-1.5-flash\", provider: \"squidley.integration.provider-google-ai-studio\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Cerebras Llama 3.1 70B\", model: \"llama3.1-70b\", provider: \"squidley.integration.provider-cerebras\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"Cerebras Llama 3.1 8B\", model: \"llama3.1-8b\", provider: \"squidley.integration.provider-cerebras\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"OpenRouter Qwen 3.6 Plus Free\", model: \"qwen/qwen3.6-plus:free\", provider: \"squidley.integration.provider-openrouter-free\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  {\n    name: \"Qwen 3.6 Plus (OpenRouter)\",\n    model: \"qwen/qwen3.6-plus\",\n    provider: \"squidley.integration.provider-openrouter\",\n    tier: 2,\n    notes: \"Paid Qwen 3.6 Plus. Input $0.276/M, output $1.651/M, explicit cache create $0.344/M, cache read $0.028/M. Tool pricing: web_search $0.573411/1K; i2i_search $6.881/1K; t2i_search $3.44/1K; code_interpreter and web_extractor currently free.\",\n    cost_per_m_input: 0.276,\n    cost_per_m_output: 1.651,\n    thinking_mode: \"enabled\",\n  },\n  {\n    name: \"Qwen 3.5 Plus (ModelStudio Direct)\",\n    model: \"qwen3.5-plus\",\n    provider: \"squidley.integration.provider-modelstudio\",\n    tier: 2,\n    notes: \"Qwen 3.5 Plus via DashScope US direct API. Fast, capable coding model.\",\n    cost_per_m_input: 0.07,\n    cost_per_m_output: 0.28,\n  },\n  {\n    name: \"Qwen 3.6 Plus (ModelStudio Direct)\",\n    model: \"qwen3.6-plus\",\n    provider: \"squidley.integration.provider-modelstudio\",\n    tier: 2,\n    notes: \"Qwen 3.6 Plus via DashScope US direct API. Opus-level coding performance.\",\n    cost_per_m_input: 0.07,\n    cost_per_m_output: 0.28,\n  },\n  { name: \"OpenRouter Gemma 3 27B Free\", model: \"google/gemma-3-27b-it:free\", provider: \"squidley.integration.provider-openrouter-free\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"OpenRouter Kimi K2 Free\", model: \"moonshotai/kimi-k2:free\", provider: \"squidley.integration.provider-openrouter-free\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  { name: \"OpenRouter Nemotron 3 Super Free\", model: \"nvidia/nemotron-3-super-120b-a12b:free\", provider: \"squidley.integration.provider-openrouter-free\", tier: 1, notes: \"Tier 1 free cloud catalog\" },\n  {\n    name: \"GLM 5.1 (OpenRouter)\",\n    model: \"z-ai/glm-5.1\",\n    provider: \"squidley.integration.provider-openrouter\",\n    tier: 2,\n    notes: \"GLM 5.1 via OpenRouter. Input $0.50/M, output $1.50/M.\",\n    cost_per_m_input: 0.50,\n    cost_per_m_output: 1.50,\n    active: true,\n  },\n  {\n    name: \"GLM 5.1 (ZAI Direct)\",\n    model: \"glm-5.1\",\n    provider: \"squidley.integration.provider-zai\",\n    tier: 2,\n    notes: \"GLM 5.1 via ZAI direct (open.bigmodel.cn). Input $0.50/M, output $1.50/M.\",\n    cost_per_m_input: 0.50,\n    cost_per_m_output: 1.50,\n    active: true,\n  },\n];\n\nconst LITE_ROLE_EXPANSION: Record<string, ModelRole[]> = {\n  chat: [\"chat\", \"fallback-chat\"],\n  code: [\"code\", \"fallback-code\", \"grimoire\", \"agent-planner\", \"code-review\"],\n  reason: [\"reason\", \"agent\"],\n  classify: [\"classify\"],\n  vision: [\"vision\", \"vision-ocr\"],\n};\n\nfunction resolveStateDir(baseDir?: string): string {\n  const stateDir = process.env[\"SQUIDLEY_STATE_DIR\"]?.trim();\n  if (stateDir) return resolve(stateDir);\n  const base = baseDir ?? process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n  return resolve(base, \"state\");\n}\n\nfunction readLiteDefaults(baseDir?: string): LiteDefaults {\n  try {\n    const base = baseDir ?? process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const raw = readFileSync(join(base, \"config\", \"lite-defaults.json\"), \"utf-8\");\n    return JSON.parse(raw) as LiteDefaults;\n  } catch {\n    return {\n      defaults: {\n        chat: { model: \"qwen3.5:4b\", provider: \"ollama\" },\n        code: { model: \"qwen3.5:9b\", provider: \"ollama\" },\n        classify: { model: \"qwen3.5:4b\", provider: \"ollama\" },\n        reason: { model: \"qwen3.5:9b\", provider: \"ollama\" },\n        vision: null,\n      },\n      liteMode: true,\n      cloudEnabled: false,\n    };\n  }\n}\n\nfunction providerServiceId(provider: string): string {\n  return PROVIDER_SERVICE_IDS[provider] ?? provider;\n}\n\nfunction tierForProvider(provider: string): 0 | 1 | 2 | 3 {\n  if (provider.includes(\"provider-ollama\") || provider.includes(\"provider-llamacpp\")) return 0;\n  if (provider.includes(\"provider-groq\") || provider.includes(\"provider-google-ai-studio\") || provider.includes(\"provider-cerebras\") || provider.includes(\"provider-openrouter-free\")) return 1;\n  if (provider.includes(\"provider-openrouter\") || provider.includes(\"provider-modelstudio\") || provider.includes(\"provider-zai\")) return 2;\n  return 3;\n}\n\nfunction displayNameForModel(model: string): string {\n  const qwenMatch = model.match(/^qwen3\\.5:(\\d+)b$/i);\n  if (qwenMatch) return \"Qwen 3.5 \" + qwenMatch[1] + \"B\";\n  if (model === \"arcee-ai/trinity-large-thinking\") return \"Arcee Trinity Large Thinking\";\n  return model;\n}\n\nfunction expandLiteRoles(defaults: LiteDefaults[\"defaults\"]): Partial<Record<ModelRole, string>> {\n  const roles: Partial<Record<ModelRole, string>> = {};\n  for (const [key, value] of Object.entries(defaults)) {\n    if (!value) continue;\n    const expanded = LITE_ROLE_EXPANSION[key] ?? [];\n    for (const role of expanded) roles[role] = value.model;\n  }\n  return roles;\n}\n\nfunction uuid(): string {\n  return randomUUID();\n}\n\nfunction rowToEntry(row: ModelRow, roles: ModelRole[]): ModelEntry {\n  return {\n    id: row.id,\n    name: row.name,\n    model: row.model,\n    provider: row.provider,\n    tier: row.tier ?? tierForProvider(row.provider),\n    roles,\n    max_tokens: row.max_tokens,\n    active: row.active === 1,\n    notes: row.notes,\n    cost_per_m_input: row.cost_per_m_input ?? null,\n    cost_per_m_output: row.cost_per_m_output ?? null,\n    thinking_mode: (row.thinking_mode as \"default\" | \"enabled\" | \"disabled\") ?? \"default\",\n    created_at: row.created_at,\n  };\n}\n\nexport class ModelRegistry {\n  private db: InstanceType<typeof Database>;\n  private dbPath: string;\n  private bootstrapSource: \"database\" | \"lite-defaults\" = \"database\";\n  private healthHint: string | null = null;\n  private cloudEnabled = true;\n\n  constructor(baseDir: string) {\n    const stateDir = resolveStateDir(baseDir);\n    mkdirSync(stateDir, { recursive: true });\n    this.dbPath = join(stateDir, \"nous-registry.db\");\n    const liteDefaults = readLiteDefaults(baseDir);\n    this.cloudEnabled = liteDefaults.cloudEnabled;\n\n    try {\n      this.db = new Database(this.dbPath);\n      this.db.pragma(\"journal_mode = WAL\");\n      this.initializeSchema();\n      this.ensureSeeded(liteDefaults);\n      this.ensureTierCatalog();\n      this.ensureRoleplayModel();\n      this.ensureTrinityModel();\n    } catch (err) {\n      console.error(\"[nous] registry corrupt, falling back to lite defaults:\", err);\n      this.db = new Database(\":memory:\");\n      this.bootstrapSource = \"lite-defaults\";\n      this.healthHint = \"Registry corrupt — loaded lite-defaults.json in recovery mode.\";\n      this.initializeSchema();\n      this.seedLiteDefaults(liteDefaults);\n      this.ensureTierCatalog();\n      this.ensureRoleplayModel();\n      this.ensureTrinityModel();\n    }\n  }\n\n  private initializeSchema(): void {\n    this.db.exec(`\n      CREATE TABLE IF NOT EXISTS models (\n        id               TEXT PRIMARY KEY,\n        name             TEXT NOT NULL,\n        model            TEXT NOT NULL,\n        provider         TEXT NOT NULL,\n        tier             INTEGER NOT NULL DEFAULT 2,\n        role             TEXT,\n        max_tokens       INTEGER,\n        active           INTEGER NOT NULL DEFAULT 1,\n        notes            TEXT,\n        cost_per_m_input REAL,\n        cost_per_m_output REAL,\n        thinking_mode    TEXT DEFAULT 'default',\n        created_at       TEXT NOT NULL\n      );\n    `);\n\n    this.db.exec(`\n      CREATE TABLE IF NOT EXISTS role_assignments (\n        role     TEXT PRIMARY KEY,\n        model_id TEXT NOT NULL\n      );\n    `);\n\n    try { this.db.exec(\"ALTER TABLE models ADD COLUMN cost_per_m_input REAL\"); } catch {}\n    try { this.db.exec(\"ALTER TABLE models ADD COLUMN cost_per_m_output REAL\"); } catch {}\n    try { this.db.exec(\"ALTER TABLE models ADD COLUMN thinking_mode TEXT DEFAULT 'default'\"); } catch {}\n    try { this.db.exec(\"ALTER TABLE models ADD COLUMN tier INTEGER NOT NULL DEFAULT 2\"); } catch {}\n\n    const assignCount = (this.db.prepare(\"SELECT COUNT(*) as n FROM role_assignments\").get() as { n: number }).n;\n    if (assignCount === 0) {\n      this.db.exec(`\n        INSERT OR IGNORE INTO role_assignments (role, model_id)\n        SELECT role, id FROM models WHERE role IS NOT NULL AND role != ''\n      `);\n    }\n  }\n\n  private ensureRoleplayModel(): void {\n    const existing = this.db.prepare(\"SELECT id FROM models WHERE model = ? AND provider = ?\")\n      .get(\"MiniMax-M2.7-her\", \"squidley.integration.provider-minimax\") as { id: string } | undefined;\n    let modelId: string;\n    if (existing) {\n      modelId = existing.id;\n    } else {\n      modelId = uuid();\n      this.db.prepare(`\n        INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)\n        VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)\n      `).run({\n        id: modelId,\n        name: \"MiniMax M2.7 Her\",\n        model: \"MiniMax-M2.7-her\",\n        provider: \"squidley.integration.provider-minimax\",\n        tier: 3,\n        max_tokens: null,\n        active: 1,\n        notes: \"Roleplay-optimized — companions, personas, narrative, character work\",\n        cost_per_m_input: 0.30,\n        cost_per_m_output: 1.20,\n        thinking_mode: \"default\",\n        created_at: new Date().toISOString(),\n      });\n    }\n    const roleAssignment = this.db.prepare(\"SELECT model_id FROM role_assignments WHERE role = 'roleplay'\").get() as { model_id: string } | undefined;\n    if (!roleAssignment) {\n      this.db.prepare(\"INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES ('roleplay', ?)\").run(modelId);\n    }\n  }\n\n  private ensureTrinityModel(): void {\n    const existing = this.db.prepare(\"SELECT id FROM models WHERE model = ? AND provider = ?\")\n      .get(\"arcee-ai/trinity-large-thinking\", \"squidley.integration.provider-openrouter\") as { id: string } | undefined;\n    if (existing) return;\n    this.db.prepare(`\n      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)\n      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)\n    `).run({\n      id: uuid(),\n      name: \"Arcee Trinity Large Thinking\",\n      model: \"arcee-ai/trinity-large-thinking\",\n      provider: \"squidley.integration.provider-openrouter\",\n      tier: 2,\n      max_tokens: 262144,\n      active: 1,\n      notes: \"Arcee AI reasoning model — strong on PinchBench, agentic workloads, and reasoning tasks. 262K context.\",\n      cost_per_m_input: 0.22,\n      cost_per_m_output: 0.85,\n      thinking_mode: \"default\",\n      created_at: new Date().toISOString(),\n    });\n  }\n\n  private ensureSeeded(liteDefaults: LiteDefaults): void {\n    const count = (this.db.prepare(\"SELECT COUNT(*) as n FROM models\").get() as { n: number }).n;\n    if (count > 0) return;\n    this.bootstrapSource = \"lite-defaults\";\n    this.healthHint = \"Registry empty — loaded lite-defaults.json.\";\n    this.seedLiteDefaults(liteDefaults);\n  }\n\n  private seedLiteDefaults(liteDefaults: LiteDefaults): void {\n    const expandedRoles = expandLiteRoles(liteDefaults.defaults);\n    const uniqueModels = new Map<string, { name: string; model: string; provider: string }>();\n\n    for (const value of Object.values(liteDefaults.defaults)) {\n      if (!value) continue;\n      const provider = providerServiceId(value.provider);\n      const key = provider + \"::\" + value.model;\n      if (!uniqueModels.has(key)) {\n        uniqueModels.set(key, {\n          name: displayNameForModel(value.model),\n          model: value.model,\n          provider,\n        });\n      }\n    }\n\n    const insert = this.db.prepare(`\n      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)\n      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)\n    `);\n    const insertRole = this.db.prepare(\"INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES (@role, @model_id)\");\n\n    const tx = this.db.transaction(() => {\n      const idsByModel = new Map<string, string>();\n      for (const model of uniqueModels.values()) {\n        const id = uuid();\n        insert.run({\n          id,\n          name: model.name,\n          model: model.model,\n          provider: model.provider,\n          tier: tierForProvider(model.provider),\n          max_tokens: null,\n          active: 1,\n          notes: \"Bootstrapped from lite-defaults.json\",\n          cost_per_m_input: null,\n          cost_per_m_output: null,\n          thinking_mode: \"default\",\n          created_at: new Date().toISOString(),\n        });\n        idsByModel.set(model.model, id);\n      }\n      for (const [role, modelName] of Object.entries(expandedRoles) as Array<[ModelRole, string]>) {\n        const modelId = idsByModel.get(modelName);\n        if (modelId) insertRole.run({ role, model_id: modelId });\n      }\n    });\n\n    tx();\n  }\n\n  private ensureTierCatalog(): void {\n    const insert = this.db.prepare(`\n      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)\n      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)\n    `);\n    const tx = this.db.transaction(() => {\n      for (const entry of BUILTIN_TIER_CATALOG) {\n        const existing = this.db.prepare(\"SELECT id FROM models WHERE model = ? AND provider = ?\").get(entry.model, entry.provider) as { id: string } | undefined;\n        if (existing) {\n          const activeClause = entry.active !== undefined ? \", active = ?\" : \"\";\n          const activeParams = entry.active !== undefined ? [entry.active ? 1 : 0] : [];\n          this.db.prepare(`\n            UPDATE models\n            SET tier = ?,\n                notes = COALESCE(notes, ?),\n                max_tokens = COALESCE(max_tokens, ?),\n                cost_per_m_input = COALESCE(cost_per_m_input, ?),\n                cost_per_m_output = COALESCE(cost_per_m_output, ?),\n                thinking_mode = COALESCE(thinking_mode, ?)${activeClause}\n            WHERE id = ?\n          `).run(\n            entry.tier,\n            entry.notes,\n            entry.max_tokens ?? null,\n            entry.cost_per_m_input ?? null,\n            entry.cost_per_m_output ?? null,\n            entry.thinking_mode ?? \"default\",\n            ...activeParams,\n            existing.id,\n          );\n          continue;\n        }\n        insert.run({\n          id: uuid(),\n          name: entry.name,\n          model: entry.model,\n          provider: entry.provider,\n          tier: entry.tier,\n          max_tokens: entry.max_tokens ?? null,\n          active: entry.active ? 1 : 0,\n          notes: entry.notes,\n          cost_per_m_input: entry.cost_per_m_input ?? null,\n          cost_per_m_output: entry.cost_per_m_output ?? null,\n          thinking_mode: entry.thinking_mode ?? \"default\",\n          created_at: new Date().toISOString(),\n        });\n      }\n    });\n    tx();\n  }\n\n  private buildRolesMap(): Map<string, ModelRole[]> {\n    const assignments = this.db.prepare(\"SELECT role, model_id FROM role_assignments\").all() as AssignmentRow[];\n    const map = new Map<string, ModelRole[]>();\n    for (const { role, model_id } of assignments) {\n      const items = map.get(model_id) ?? [];\n      items.push(role);\n      map.set(model_id, items);\n    }\n    return map;\n  }\n\n  list(): ModelEntry[] {\n    const rows = this.db.prepare(\"SELECT * FROM models ORDER BY created_at ASC\").all() as ModelRow[];\n    const rolesMap = this.buildRolesMap();\n    return rows.map((row) => rowToEntry(row, rolesMap.get(row.id) ?? []));\n  }\n\n  get(id: string): ModelEntry | null {\n    const row = this.db.prepare(\"SELECT * FROM models WHERE id = ?\").get(id) as ModelRow | undefined;\n    if (!row) return null;\n    const assignments = this.db.prepare(\"SELECT role FROM role_assignments WHERE model_id = ?\").all(id) as Array<{ role: ModelRole }>;\n    return rowToEntry(row, assignments.map((item) => item.role));\n  }\n\n  add(entry: Omit<ModelEntry, \"id\" | \"created_at\" | \"roles\" | \"tier\"> & Partial<Pick<ModelEntry, \"tier\">>): ModelEntry {\n    const existing = this.db.prepare(\"SELECT id FROM models WHERE model = ? AND provider = ?\").get(entry.model, entry.provider) as { id: string } | undefined;\n    if (existing) return this.get(existing.id)!;\n\n    const id = uuid();\n    const created_at = new Date().toISOString();\n    this.db.prepare(`\n      INSERT INTO models (id, name, model, provider, tier, max_tokens, active, notes, cost_per_m_input, cost_per_m_output, thinking_mode, created_at)\n      VALUES (@id, @name, @model, @provider, @tier, @max_tokens, @active, @notes, @cost_per_m_input, @cost_per_m_output, @thinking_mode, @created_at)\n    `).run({\n      id,\n      name: entry.name,\n      model: entry.model,\n      provider: entry.provider,\n      tier: entry.tier ?? tierForProvider(entry.provider),\n      max_tokens: entry.max_tokens ?? null,\n      active: entry.active ? 1 : 0,\n      notes: entry.notes ?? null,\n      cost_per_m_input: entry.cost_per_m_input ?? null,\n      cost_per_m_output: entry.cost_per_m_output ?? null,\n      thinking_mode: entry.thinking_mode ?? \"default\",\n      created_at,\n    });\n    return this.get(id)!;\n  }\n\n  update(id: string, patch: Partial<Omit<ModelEntry, \"id\" | \"created_at\" | \"roles\">>): ModelEntry | null {\n    const existing = this.get(id);\n    if (!existing) return null;\n\n    const fields: string[] = [];\n    const values: Record<string, unknown> = { id };\n\n    if (patch.name !== undefined) { fields.push(\"name = @name\"); values.name = patch.name; }\n    if (patch.model !== undefined) { fields.push(\"model = @model\"); values.model = patch.model; }\n    if (patch.provider !== undefined) { fields.push(\"provider = @provider\"); values.provider = patch.provider; }\n    if (\"tier\" in patch) { fields.push(\"tier = @tier\"); values.tier = patch.tier ?? tierForProvider(patch.provider ?? existing.provider); }\n    if (\"max_tokens\" in patch) { fields.push(\"max_tokens = @max_tokens\"); values.max_tokens = patch.max_tokens ?? null; }\n    if (patch.active !== undefined) { fields.push(\"active = @active\"); values.active = patch.active ? 1 : 0; }\n    if (\"notes\" in patch) { fields.push(\"notes = @notes\"); values.notes = patch.notes ?? null; }\n    if (\"cost_per_m_input\" in patch) { fields.push(\"cost_per_m_input = @cost_per_m_input\"); values.cost_per_m_input = patch.cost_per_m_input ?? null; }\n    if (\"cost_per_m_output\" in patch) { fields.push(\"cost_per_m_output = @cost_per_m_output\"); values.cost_per_m_output = patch.cost_per_m_output ?? null; }\n    if (\"thinking_mode\" in patch) { fields.push(\"thinking_mode = @thinking_mode\"); values.thinking_mode = patch.thinking_mode ?? \"default\"; }\n\n    if (fields.length === 0) return existing;\n    this.db.prepare(\"UPDATE models SET \" + fields.join(\", \") + \" WHERE id = @id\").run(values);\n    return this.get(id);\n  }\n\n  delete(id: string): boolean {\n    this.db.prepare(\"DELETE FROM role_assignments WHERE model_id = ?\").run(id);\n    const result = this.db.prepare(\"DELETE FROM models WHERE id = ?\").run(id);\n    return result.changes > 0;\n  }\n\n  getRoles(): Record<ModelRole, ModelEntry | null> {\n    const entries = this.list();\n    const result = {} as Record<ModelRole, ModelEntry | null>;\n    for (const role of ALL_MODEL_ROLES) {\n      result[role] = entries.find((entry) => entry.active && entry.roles.includes(role)) ?? null;\n    }\n    return result;\n  }\n\n  assignRole(role: ModelRole, modelId: string | null): void {\n    if (modelId) {\n      this.db.prepare(\"INSERT OR REPLACE INTO role_assignments (role, model_id) VALUES (?, ?)\").run(role, modelId);\n    } else {\n      this.db.prepare(\"DELETE FROM role_assignments WHERE role = ?\").run(role);\n    }\n  }\n\n  getHealth(): ModelRegistryHealth {\n    const entries = this.list();\n    const roles = this.getRoles();\n    const activeCloudModels = entries.filter((entry) => !entry.provider.includes(\"provider-ollama\") && !entry.provider.includes(\"provider-llamacpp\"));\n    const missingCoreRoles = CORE_ROLE_REQUIREMENTS.filter((role) => !roles[role]);\n\n    let trust: RegistryTrust = \"trusted\";\n    let hint = this.healthHint;\n\n    if (this.healthHint?.toLowerCase().includes(\"corrupt\")) {\n      trust = \"degraded\";\n    } else if (this.bootstrapSource === \"lite-defaults\") {\n      trust = \"verified\";\n      hint = hint ?? \"Lite defaults loaded.\";\n    } else if (missingCoreRoles.length > 0) {\n      trust = \"verified\";\n      hint = hint ?? (\"Unassigned roles: \" + missingCoreRoles.join(\", \"));\n    }\n\n    return {\n      trust,\n      mode: !this.cloudEnabled && activeCloudModels.length === 0 ? \"lite\" : \"full\",\n      dbPath: this.dbPath,\n      contract: NOUS_CONTRACT,\n      hint,\n      cloudEnabled: this.cloudEnabled,\n      bootstrapSource: this.bootstrapSource,\n    };\n  }\n\n  close(): void {\n    this.db.close();\n  }\n}\n\nlet _registry: ModelRegistry | null = null;\n\nexport function getModelRegistry(baseDir?: string): ModelRegistry {\n  if (!_registry) {\n    const base = baseDir ?? process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    _registry = new ModelRegistry(base);\n  }\n  return _registry;\n}\n",
