              "path": "apps/api/src/config/model-roles.ts",
              "content": "/**\n * Squidley V2 — Model Role Registry\n * ============================================================\n * Single source of truth for which model handles each semantic role.\n * All hardcoded model strings in routes and modules should reference\n * this registry so model swaps happen in one place.\n *\n * Doctrine Principle 10 — Tiered Model Isolation:\n *   Tier 0 (local): routing, identity, classification, heartbeat\n *   Tier 1 (free cloud): fallback only\n *   Tier 2 (paid cloud): user-facing responses ONLY\n *   Tier 3 (premium): break-glass escalation\n *\n * Primary roles:\n *   chat          — conversational, fast (Colloquium/Symposium are NOT here — see squidley-voice.ts)\n *   code          — code generation and review\n *   agent         — structured JSON output, multi-step reasoning\n *   classify      — lightweight task classification (Brain Map) — LOCAL ONLY\n *   vision        — image/document extraction (Archivum cloud path)\n *   reason        — deep reasoning, security review\n *   grimoire      — intent -> shell plan translation\n *   codex         — iterative code agent loop\n *\n * Extended roles:\n *   fallback-chat  — chat failover when primary fails\n *   fallback-code  — code failover when primary fails\n *   agent-planner  — high-level agent planning and task decomposition\n *   vision-ocr     — OCR and dense document text extraction\n *   code-review    — dedicated code review and diff analysis\n * ============================================================\n */\n\nexport const MODEL_ROLES = {\n  chat: {\n    model:    \"xiaomi/mimo-v2-pro\",\n    provider: \"squidley.integration.provider-openrouter\",\n    params:   { max_tokens: 2048 },\n  },\n  code: {\n    model:    \"xiaomi/mimo-v2-pro\",\n    provider: \"squidley.integration.provider-openrouter\",\n    params:   { max_tokens: 4096 },\n  },\n  agent: {\n    model:    \"z-ai/glm-5-turbo\",\n    provider: \"squidley.integration.provider-zai\",\n    params:   { max_tokens: 2048 },\n  },\n  classify: {\n    model:    \"qwen3.5:4b\",\n    provider: \"squidley.integration.provider-ollama\",\n    params:   { max_tokens: 256 },\n  },\n  vision: {\n    model:    \"gpt-5.4-mini\",\n    provider: \"squidley.integration.provider-openai\",\n    params:   { max_tokens: 1024 },\n  },\n  reason: {\n    model:    \"claude-sonnet-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    params:   { max_tokens: 4096 },\n  },\n  grimoire: {\n    model:    \"z-ai/glm-5-turbo\",\n    provider: \"squidley.integration.provider-zai\",\n    params:   { max_tokens: 2048 },\n  },\n  codex: {\n    model:    \"claude-sonnet-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    params:   { max_tokens: 4096 },\n  },\n  \"fallback-chat\": {\n    model:    \"xiaomi/mimo-v2-pro\",\n    provider: \"squidley.integration.provider-openrouter\",\n    params:   { max_tokens: 1024 },\n  },\n  \"fallback-code\": {\n    model:    \"z-ai/glm-5-turbo\",\n    provider: \"squidley.integration.provider-zai\",\n    params:   { max_tokens: 4096 },\n  },\n  \"agent-planner\": {\n    model:    \"claude-sonnet-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    params:   { max_tokens: 4096 },\n  },\n  \"vision-ocr\": {\n    model:    \"gpt-5.4-mini\",\n    provider: \"squidley.integration.provider-openai\",\n    params:   { max_tokens: 2048 },\n  },\n  \"code-review\": {\n    model:    \"claude-sonnet-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    params:   { max_tokens: 4096 },\n  },\n} as const;\n\nexport type ModelRole = keyof typeof MODEL_ROLES;\n\n/**\n * Per-role fallback chains — ordered list of {model, provider} pairs.\n * When primary fails (error OR empty response), try next in chain.\n * Max 2 fallback hops per request.\n *\n * Strategy: OpenRouter primary (burn credits), direct provider fallback.\n * MiMo stays OpenRouter-only (no direct API available).\n */\n/**\n * Per-role fallback chains.\n * OpenRouter ONLY for MiMo models (Flash, V2 Pro, V2 Omni).\n * Everything else uses direct provider keys.\n */\nexport const ROLE_FALLBACK_CHAINS: Record<string, Array<{ model: string; provider: string }>> = {\n  chat: [\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n    { model: \"xiaomi/mimo-v2-flash\",        provider: \"squidley.integration.provider-openrouter\" },\n  ],\n  code: [\n    { model: \"xiaomi/mimo-v2-pro\",          provider: \"squidley.integration.provider-openrouter\" },\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n  ],\n  agent: [\n    { model: \"gpt-5.4-mini\",               provider: \"squidley.integration.provider-openai\" },\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n    { model: \"xiaomi/mimo-v2-flash\",        provider: \"squidley.integration.provider-openrouter\" },\n  ],\n  classify: [\n    { model: \"qwen2.5:7b-instruct\",        provider: \"squidley.integration.provider-ollama\" },\n  ],\n  vision: [\n    { model: \"xiaomi/mimo-v2-omni\",         provider: \"squidley.integration.provider-openrouter\" },\n    { model: \"gpt-5.4-mini\",               provider: \"squidley.integration.provider-openai\" },\n    { model: \"z-ai/glm-5\",                 provider: \"squidley.integration.provider-zai\" },\n  ],\n  reason: [\n    { model: \"xiaomi/mimo-v2-pro\",          provider: \"squidley.integration.provider-openrouter\" },\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n  ],\n  grimoire: [\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n    { model: \"xiaomi/mimo-v2-flash\",        provider: \"squidley.integration.provider-openrouter\" },\n  ],\n  codex: [\n    { model: \"claude-sonnet-4-6\",           provider: \"squidley.integration.provider-anthropic\" },\n    { model: \"MiniMax-M1\",                  provider: \"squidley.integration.provider-minimax\" },\n  ],\n};\n",
