              "path": "apps/api/src/config/peers.ts",
              "content": "/**\n * Peer Machines — Squidley distributed cluster\n * ================================================\n * Machines connected via Tailscale that can accept work.\n */\n\nexport interface PeerMachine {\n  name: string;\n  tailscale_ip: string;\n  worker_port: number;\n  gpu: string;\n  vram_gb: number;\n  worker_url: string;\n}\n\nexport const PEER_MACHINES: Record<string, PeerMachine> = {\n  poptart: {\n    name: \"Pop Tart\",\n    tailscale_ip: \"100.111.206.3\",\n    worker_port: 8765,\n    gpu: \"AMD RX 6800\",\n    vram_gb: 16,\n    worker_url: \"http://100.111.206.3:8765\",\n  },\n};\n\nexport function getPeer(id: string): PeerMachine | null {\n  return PEER_MACHINES[id] ?? null;\n}\n\nexport function listPeers(): PeerMachine[] {\n  return Object.values(PEER_MACHINES);\n}\n",
