              "path": "apps/api/src/config/personality-judge.ts",
              "content": "/**\n * Personality Judge — Cost Controls\n * ====================================\n * Hard limits. Never bypassed. Never configurable at runtime.\n */\n\nexport const JUDGE_LIMITS = {\n  /** Hard ceiling on judge calls per day */\n  daily_judge_calls_max: 100,\n  /** Warn when daily judge cost exceeds this */\n  daily_cost_warning_threshold: 2.00,\n  /** Block ALL judge calls when daily cost exceeds this */\n  daily_cost_hard_limit: 5.00,\n  /** Max models in a single personality benchmark run */\n  max_models_per_run: 5,\n  /** Truncate model responses to this many tokens before sending to judge */\n  response_truncation_tokens: 300,\n  /** Max tokens for judge response (JSON only) */\n  judge_max_tokens: 150,\n} as const;\n\n/** Judge model options — default is Budget (Sonnet) */\nexport const JUDGE_MODELS = {\n  budget: {\n    id: \"claude-sonnet-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    label: \"Claude Sonnet 4.6\",\n    cost_per_m_input: 3.00,\n    cost_per_m_output: 15.00,\n  },\n  standard: {\n    id: \"claude-opus-4-6\",\n    provider: \"squidley.integration.provider-anthropic\",\n    label: \"Claude Opus 4.6\",\n    cost_per_m_input: 15.00,\n    cost_per_m_output: 75.00,\n  },\n} as const;\n\nexport type JudgeTier = keyof typeof JUDGE_MODELS;\n\n/** Estimate cost for a personality benchmark run */\nexport function estimatePersonalityCost(\n  modelCount: number,\n  testCount: number,\n  judgeTier: JudgeTier,\n): { modelCost: number; judgeCost: number; totalCost: number; judgeCallCount: number } {\n  const judgeModel = JUDGE_MODELS[judgeTier];\n  const judgeCallCount = modelCount * testCount;\n  // ~600 input tokens + ~80 output tokens per judge call\n  const judgeCost = judgeCallCount * ((600 / 1_000_000) * judgeModel.cost_per_m_input + (80 / 1_000_000) * judgeModel.cost_per_m_output);\n  // ~200 input + ~100 output tokens per model call (personality prompts are short)\n  const modelCost = judgeCallCount * ((200 / 1_000_000) * 0.50 + (100 / 1_000_000) * 1.50); // estimate with cheap model\n  return {\n    modelCost: Math.round(modelCost * 10000) / 10000,\n    judgeCost: Math.round(judgeCost * 10000) / 10000,\n    totalCost: Math.round((modelCost + judgeCost) * 10000) / 10000,\n    judgeCallCount,\n  };\n}\n\n// ── Daily tracker (in-memory, resets on restart) ────────────────────────────\n\nlet dailyJudgeCalls = 0;\nlet dailyCost = 0;\nlet lastResetDate = new Date().toISOString().slice(0, 10);\n\nfunction resetIfNewDay() {\n  const today = new Date().toISOString().slice(0, 10);\n  if (today !== lastResetDate) {\n    dailyJudgeCalls = 0;\n    dailyCost = 0;\n    lastResetDate = today;\n  }\n}\n\nexport function canRunJudge(): { allowed: boolean; reason?: string } {\n  resetIfNewDay();\n  if (dailyJudgeCalls >= JUDGE_LIMITS.daily_judge_calls_max) {\n    return { allowed: false, reason: `Daily judge call limit reached (${dailyJudgeCalls}/${JUDGE_LIMITS.daily_judge_calls_max})` };\n  }\n  if (dailyCost >= JUDGE_LIMITS.daily_cost_hard_limit) {\n    return { allowed: false, reason: `Daily judge cost limit reached ($${dailyCost.toFixed(2)}/$${JUDGE_LIMITS.daily_cost_hard_limit.toFixed(2)})` };\n  }\n  return { allowed: true };\n}\n\nexport function recordJudgeCall(cost: number) {\n  resetIfNewDay();\n  dailyJudgeCalls++;\n  dailyCost += cost;\n}\n\nexport function getJudgeUsage(): { calls: number; cost: number; limit: number; costLimit: number } {\n  resetIfNewDay();\n  return { calls: dailyJudgeCalls, cost: dailyCost, limit: JUDGE_LIMITS.daily_judge_calls_max, costLimit: JUDGE_LIMITS.daily_cost_hard_limit };\n}\n",
